UPDATE sys_document
project_id = #{projectId}, task_id = #{taskId}, name = #{name}, category = #{category}, description = #{description}, parent_id = #{parentId}, report_id = #{reportId}, updated_at = NOW()
WHERE id = #{id}

UPDATE sys_document
SET status = 'deleted', updated_at = NOW()
WHERE id = #{id}

UPDATE sys_document
SET download_count = download_count + 1
WHERE id = #{id}
